module RefModule(
	input clk,
	input reset,
	output [3:0] count);reg [3:0] unused_count_reg = 4'b0000;

	always @(posedge clk or posedge reset) begin
		if (reset)
			unused_count_reg <= 4'b0000;
		else
			unused_count_reg <= unused_count_reg + 1;
	end

	assign count = unused_count_reg;

endmodule
